<#
Install-AdminLauncher.ps1
Deploys ADMPASS.exe, trusts its signing cert, sets ACLs, and adds it to system PATH.
Does NOT handle credentials — that's ADMPASS.exe's job (-Admin/-Pass, -Cred, or -UpdatePassword).

Usage:

ManageEngine / SYSTEM:
  powershell -NoProfile -ExecutionPolicy Bypass -File Install-AdminLauncher.ps1

  SYSTEM account is detected automatically.
  Installation remains non-interactive.
  No credential prompt is shown.

Manual execution:
  powershell -NoProfile -ExecutionPolicy Bypass -File Install-AdminLauncher.ps1

  After installation, ADMPASS -UpdatePassword
  is launched automatically and prompts for credentials.
  
Exit codes:
  0 = success
  1 = general failure
  2 = ADMPASS.exe signature validation failed
  4 = not elevated and cannot elevate in current (non-interactive) context
#>

param()

# ============================================================
# CONFIG
# ============================================================

$MainDir          = "C:\Windows\System32\Acceleron\"
$BaseDir          = Join-Path $MainDir "AdminLauncher"
$CertDir          = Join-Path $MainDir "Certificate"

$CredFile         = Join-Path $BaseDir 'cred.dat'
$ExeWrapperPath   = Join-Path $BaseDir "ADMPASS.exe"
$CertPath         = Join-Path $CertDir "GainwellWallpaper.cer"
$LogFile          = Join-Path $BaseDir "install.log"

$PinnedThumbprint = "ECACA66CD84B620E80C8329A253DE85149666D6E"

$IsSystem = ([Security.Principal.WindowsIdentity]::GetCurrent().IsSystem)
$IsAdmin  = ([Security.Principal.WindowsPrincipal] `
            [Security.Principal.WindowsIdentity]::GetCurrent()).IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)


# ============================================================
# LOGGING
# ============================================================

function Write-Log {
    param(
        [string]$Message,
        [string]$Level = "INFO"
    )

    switch ($Level.ToUpper()) {

        "SUCCESS" { Write-Host $Message -ForegroundColor Green }
        "ERROR"   { Write-Host $Message -ForegroundColor Red }
        "WARN"    { Write-Host $Message -ForegroundColor Yellow }
        "ACTION"  { Write-Host $Message -ForegroundColor Cyan }

        default   { Write-Host $Message }
    }
}

function Exit-Install {
    param([int]$Code, [string]$Message)
    if ($Code -eq 0) { Write-Log $Message "INFO" } else { Write-Log $Message "ERROR" }
    exit $Code
}

# ============================================================
# ELEVATION
# ============================================================

if (-not $IsAdmin -and -not $IsSystem) {

    Write-Log "Not elevated. Relaunching elevated..." "WARN"

    $pwsh = (Get-Command pwsh -ErrorAction SilentlyContinue).Source
    if (-not $pwsh) {
        $pwsh = (Get-Command powershell).Source
    }

    if (-not $pwsh) {
        Exit-Install 1 "Cannot locate powershell executable to relaunch."
    }

    $argList = @(
        "-NoProfile",
        "-ExecutionPolicy",
        "Bypass",
        "-File",
        "`"$PSCommandPath`""
    )

    $psi = New-Object System.Diagnostics.ProcessStartInfo
    $psi.FileName  = $pwsh
    $psi.Arguments = ($argList -join ' ')
    $psi.Verb      = "runas"

    try {
        [System.Diagnostics.Process]::Start($psi) | Out-Null
    }
    catch {
        Exit-Install 1 ("Failed to relaunch elevated: {0}" -f $_)
    }

    exit 0
}

# ============================================================
# ENSURE DIRECTORIES
# ============================================================

foreach ($dir in @($BaseDir, $CertDir)) {
    if (-not (Test-Path $dir)) {
        try { New-Item -Path $dir -ItemType Directory -Force | Out-Null }
        catch { Exit-Install 1 ("Failed to create directory {0}: {1}" -f $dir, $_) }
    }
}

Write-Log "Install started..." "INFO"

# ============================================================
# CLEAN OLD FILES
# ============================================================

Remove-Item (Join-Path $BaseDir "ADMPASS.ps1") -Force -ErrorAction SilentlyContinue
Remove-Item (Join-Path $BaseDir "ADMPASS.exe") -Force -ErrorAction SilentlyContinue
New-Item -Path $CredFile -ItemType File -Force | Out-Null
Clear-Content -Path $CredFile

# ============================================================
# EMBEDDED BINARIES (BASE64)
# ============================================================

$CertBase64 = @'

'@

$ExeWrapperBase64 = @'

'@

$PolicyExeBytes = [Convert]::FromBase64String($ExeWrapperBase64)

# ============================================================
# WRITE + TRUST CERTIFICATE
# ============================================================

try {
    if (-not (Test-Path $CertPath)) {
        [IO.File]::WriteAllBytes($CertPath, [Convert]::FromBase64String($CertBase64))
    }

    foreach ($store in @("Root", "TrustedPublisher")) {
        if (-not (certutil -store $store | Select-String $PinnedThumbprint)) {
            & certutil.exe -addstore $store $CertPath | Out-Null
        }
    }
} catch {
    Exit-Install 1 ("Failed to install trust certificate: {0}" -f $_) "ERROR"
}

# ============================================================
# WRITE EXE WRAPPER (idempotent — skip if already correct)
# ============================================================

$WriteUpdateExe = $true

if (Test-Path $ExeWrapperPath) {
    $Sig = Get-AuthenticodeSignature $ExeWrapperPath
    if ($Sig.SignerCertificate -and $Sig.SignerCertificate.Thumbprint -eq $PinnedThumbprint) {
        $WriteUpdateExe = $false
        Write-Log "ADMPASS.exe already present with correct signature. Skipping rewrite." "WARN"
    }
}

if ($WriteUpdateExe) {
    try {
        [IO.File]::WriteAllBytes($ExeWrapperPath, $PolicyExeBytes)
    } catch {
        Exit-Install 1 ("Failed to write ADMPASS.exe: {0}" -f $_) "ERROR"
    }

    Start-Sleep -Seconds 2
    $Sig = Get-AuthenticodeSignature $ExeWrapperPath

    if (-not $Sig.SignerCertificate -or
        $Sig.SignerCertificate.Thumbprint -ne $PinnedThumbprint -or
        $Sig.Status -in @('HashMismatch', 'NotSigned')) {
        Exit-Install 2 "ADMPASS.exe signature validation failed after write."
    }
    Write-Log "ADMPASS.exe written and signature verified." "SUCCESS"
}

# ============================================================
# SET ACLs
# ============================================================

try {
    $aclExe = New-Object System.Security.AccessControl.FileSecurity
    $aclExe.SetAccessRuleProtection($true, $false)
    $aclExe.AddAccessRule((New-Object System.Security.AccessControl.FileSystemAccessRule("Everyone",               "ReadAndExecute", "Allow")))
    $aclExe.AddAccessRule((New-Object System.Security.AccessControl.FileSystemAccessRule("BUILTIN\Administrators", "FullControl",    "Allow")))
    $aclExe.AddAccessRule((New-Object System.Security.AccessControl.FileSystemAccessRule("NT AUTHORITY\SYSTEM",   "FullControl",    "Allow")))
    Set-Acl -Path $ExeWrapperPath -AclObject $aclExe
} catch {
    Write-Log ("Failed to set ACL on ADMPASS.exe: {0}" -f $_) "ERROR"
}

if (Test-Path $CredFile) {
    try {
        $acl = New-Object System.Security.AccessControl.FileSecurity
        $acl.SetAccessRuleProtection($true, $false)
        $acl.AddAccessRule((New-Object System.Security.AccessControl.FileSystemAccessRule("Users",                 "ReadAndExecute,Read", "Allow")))
        $acl.AddAccessRule((New-Object System.Security.AccessControl.FileSystemAccessRule("BUILTIN\Administrators","FullControl",         "Allow")))
        $acl.AddAccessRule((New-Object System.Security.AccessControl.FileSystemAccessRule("NT AUTHORITY\SYSTEM",  "FullControl",         "Allow")))
        Set-Acl -Path $CredFile -AclObject $acl
    } catch {
        Write-Log ("Failed to set ACL on cred file: {0}" -f $_) "ERROR"
    }
}

# ============================================================
# ADD BASEDIR TO SYSTEM PATH
# ============================================================

function Add-ToSystemPath {
    param([string]$PathToAdd)

    $regKey  = 'Registry::HKEY_LOCAL_MACHINE\SYSTEM\CurrentControlSet\Control\Session Manager\Environment'
    $current = (Get-ItemProperty -Path $regKey -Name Path).Path

    $normalizedAdd = $PathToAdd.TrimEnd('\')
    $entries       = $current -split ';' | ForEach-Object { $_.TrimEnd('\') }

    if ($entries -notcontains $normalizedAdd) {
        $newPath = if ($current.TrimEnd(';') -eq '') { $PathToAdd } else { "$current;$PathToAdd" }

        try {
            Set-ItemProperty -Path $regKey -Name Path -Value $newPath

            $HWND_BROADCAST   = [IntPtr]0xffff
            $WM_SETTINGCHANGE = 0x1A
            $result           = [UIntPtr]::Zero
            $sig = @'
[DllImport("user32.dll", SetLastError = true, CharSet = CharSet.Auto)]
public static extern IntPtr SendMessageTimeout(IntPtr hWnd, uint Msg, UIntPtr wParam, string lParam, uint fuFlags, uint uTimeout, out UIntPtr lpdwResult);
'@
            $type = Add-Type -MemberDefinition $sig -Name Win32SendMessageTimeout -Namespace Win32Functions -PassThru
            $type::SendMessageTimeout($HWND_BROADCAST, $WM_SETTINGCHANGE, [UIntPtr]::Zero, "Environment", 2, 5000, [ref]$result) | Out-Null
            Write-Log "Added $PathToAdd to system PATH."
        } catch {
            Write-Log ("Failed to update system PATH: {0}" -f $_) "ERROR"
        }
    } else {
        Write-Log "System PATH already contains $PathToAdd. Skipping." "WARN"
    }
}

Add-ToSystemPath -PathToAdd $BaseDir

# ============================================================
# CREDENTIAL SETUP — only for interactive/manual runs.
# ManageEngine/SYSTEM runs skip this; set credential separately.
# ============================================================

if ($IsSystem) {

    Write-Host ""
    Write-Host "Installation completed successfully." -ForegroundColor Green
	Write-Host ""
		Write-Host "Usage:" -ForegroundColor Magenta
		Write-Host "  ADMPASS -UpdatePassword" -ForegroundColor Magenta
		Write-Host "  ADMPASS -UpdatePassword <Admin> <Password>" -ForegroundColor Magenta
		Write-Host "  ADMPASS <FilePath> [args]" -ForegroundColor Magenta

}
else {

    Clear-Host

    Write-Host "Launching administrator credential setup..." -ForegroundColor Cyan
    Write-Host ""

    try {
        Write-Host ""
        Write-Host "====================================" -ForegroundColor Green
        Write-Host "Installation completed successfully." -ForegroundColor Green
        Write-Host "====================================" -ForegroundColor Green
        Write-Host ""
		Write-Host "Usage:" -ForegroundColor Magenta
		Write-Host "  ADMPASS -UpdatePassword" -ForegroundColor Magenta
		Write-Host "  ADMPASS -UpdatePassword <Admin> <Password>" -ForegroundColor Magenta
		Write-Host "  ADMPASS <FilePath> [args]" -ForegroundColor Magenta
		
		$null = Set-ItemProperty -Path "HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Policies\System" -Name "FilterAdministratorToken" -Value 0 -Type DWord
		
        & $ExeWrapperPath -UpdatePassword
    }
    catch {
        Write-Host ""
        Write-Host ("Installation failed: {0}" -f $_) -ForegroundColor Red
    }
}

Write-Host "A system restart is required for the changes to take effect." -ForegroundColor DarkYellow

Remove-Item $LogFile -Force  -ErrorAction SilentlyContinue